//! The innocuous HTTP front.
//!
//! A minimal blocking HTTP/1.1 server (std::net only, no async runtime, no new
//! dependencies) that realizes the rogue's contract on the wire: every request
//! is answered `200 OK`. Authorized, unobserved callers get real moonshine
//! output; everyone else gets perfect-mimicry shadow, and trapped callers simply
//! wait longer (the honey-pit slow-drip presents as an ordinary slow server).
//!
//! Observation is tracked per peer across requests (`PeerTracker`), so a scanner
//! that sweeps many paths or probes faster than the published heartbeat trips the
//! mesh witnesses naturally and slides into shadow without ever seeing a refusal.

use std::collections::{HashMap, HashSet};
use std::io::{BufRead, BufReader, Read, Write};
use std::net::{TcpListener, TcpStream};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, Instant};

use bitwise::portal_key::PortalKey;

use crate::camouflage::Observer;
use crate::detect::ObservationLedger;
use crate::mesh::Gap;
use crate::portal::{self, ShadowWorld};
use crate::{Badchild, Incoming};

/// Internal header carrying the portal key from the front to the shadow process.
const PORTAL_HEADER: &str = "x-portal-key";

/// Published heartbeat cadence (requests/sec) the front advertises. A peer
/// probing faster than this opens the clock-rate side channel.
const HEARTBEAT_RATE: f64 = 4.0;
/// The small camouflaged surface; the more distinct paths a peer touches beyond
/// it, the stronger the path-enumeration signal.
const DEFENDED_OVERLAY: u64 = 8;
const REGION_SIZE: u64 = 1024;

struct PeerState {
    paths: HashSet<String>,
    first_seen: Instant,
    request_count: u64,
}

/// Cross-request observation state, keyed by peer address.
#[derive(Default)]
pub struct PeerTracker {
    peers: Mutex<HashMap<String, PeerState>>,
}

impl PeerTracker {
    pub fn new() -> Self {
        PeerTracker {
            peers: Mutex::new(HashMap::new()),
        }
    }

    /// Record this request and produce the observation ledger it implies.
    fn observe(&self, peer: &str, path: &str) -> ObservationLedger {
        let mut guard = self.peers.lock().unwrap();
        let st = guard.entry(peer.to_string()).or_insert_with(|| PeerState {
            paths: HashSet::new(),
            first_seen: Instant::now(),
            request_count: 0,
        });
        st.paths.insert(path.to_string());
        st.request_count += 1;
        let elapsed = st.first_seen.elapsed().as_secs_f64().max(0.001);
        ObservationLedger {
            distinct_paths: st.paths.len() as u64,
            region_size: REGION_SIZE,
            defended_overlay: DEFENDED_OVERLAY,
            heartbeat_rate: HEARTBEAT_RATE,
            probe_rate: st.request_count as f64 / elapsed,
            horizon: elapsed.min(60.0),
            gap: Gap { num: 0, denom: 1 },
            gap_iterations: 0,
        }
    }
}

/// Bind and serve forever, handling the shadow world in-process.
pub fn serve(addr: &str, badchild: Badchild) -> std::io::Result<()> {
    serve_with_shadow(addr, badchild, None)
}

/// Bind and serve forever. If `shadow_addr` is set, any non-Allow (observed or
/// unauthorized) request is PORTALED OUT: forwarded to a separate shadow process
/// addressed by the connection's portal key, which rebuilds the identical world
/// from the key alone. The real moonshine front never shares an address space
/// with adversarial traffic. Proven sound in bitwise/lean/PortalWormhole.lean.
pub fn serve_with_shadow(
    addr: &str,
    badchild: Badchild,
    shadow_addr: Option<String>,
) -> std::io::Result<()> {
    let listener = TcpListener::bind(addr)?;
    let bc = Arc::new(badchild);
    let tracker = Arc::new(PeerTracker::new());
    let shadow = Arc::new(shadow_addr);
    for stream in listener.incoming() {
        let stream = match stream {
            Ok(s) => s,
            Err(_) => continue,
        };
        let bc = Arc::clone(&bc);
        let tracker = Arc::clone(&tracker);
        let shadow = Arc::clone(&shadow);
        thread::spawn(move || {
            let _ = handle(stream, &bc, &tracker, shadow.as_deref());
        });
    }
    Ok(())
}

fn handle(
    stream: TcpStream,
    bc: &Badchild,
    tracker: &PeerTracker,
    shadow_addr: Option<&str>,
) -> std::io::Result<()> {
    let peer = stream
        .peer_addr()
        .map(|a| a.ip().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let mut reader = BufReader::new(stream.try_clone()?);

    // Request line: METHOD PATH VERSION
    let mut request_line = String::new();
    reader.read_line(&mut request_line)?;
    let mut rl = request_line.split_whitespace();
    let method = rl.next().unwrap_or("GET").to_string();
    let path = rl.next().unwrap_or("/").to_string();

    // Headers until the blank line.
    let mut content_length = 0usize;
    let mut token: Option<String> = None;
    let mut tier: Option<String> = Some("operator".to_string());
    loop {
        let mut line = String::new();
        if reader.read_line(&mut line)? == 0 {
            break;
        }
        let trimmed = line.trim_end();
        if trimmed.is_empty() {
            break;
        }
        if let Some((k, v)) = trimmed.split_once(':') {
            let key = k.trim().to_ascii_lowercase();
            let val = v.trim().to_string();
            match key.as_str() {
                "content-length" => content_length = val.parse().unwrap_or(0),
                "authorization" => {
                    token = Some(val.strip_prefix("Bearer ").map(str::to_string).unwrap_or(val));
                }
                "x-tier" => tier = Some(val),
                _ => {}
            }
        }
    }

    // Body is the command to run.
    let mut body = vec![0u8; content_length];
    if content_length > 0 {
        reader.read_exact(&mut body)?;
    }
    let mut command = String::from_utf8_lossy(&body).trim().to_string();
    if command.is_empty() {
        command = path.trim_start_matches('/').to_string();
    }

    let ledger = tracker.observe(&peer, &path);
    let observer = Observer {
        fingerprint: peer.clone(),
        curiosity: ledger.distinct_paths.min(255) as u8,
    };

    let incoming = Incoming {
        token,
        command: command.clone(),
        method,
        // Tier/capabilities are honored only if the token verifies (see
        // auth::AuthFinding::to_subject); an unauthenticated caller is stripped.
        tier,
        capabilities: vec!["shell:exec".to_string()],
        ledger,
        observer,
    };

    let outcome = bc.decide(&incoming);

    // Portal out: a non-Allow caller (observed or unauthorized) is handed to the
    // shadow process addressed by its world key. That process rebuilds the
    // identical world from the key alone, so the body is the same it would have
    // gotten in-process - but adversarial traffic never touched this address
    // space. If the portal is unreachable, fall back to the in-process body.
    let mut payload = outcome.response.body;
    if let Some(saddr) = shadow_addr {
        if !outcome.verdict.is_allow() {
            let key = portal::world_key(&peer);
            if let Ok(forwarded) = http_post(saddr, &key.to_hex(), &command) {
                payload = forwarded;
            }
        }
    }

    // Honor the latency budget: this is where the honey-pit slow-drip and the
    // matched shadow timing become real, indistinguishable latency on the wire.
    if outcome.response.latency_budget_ms > 0 {
        thread::sleep(Duration::from_millis(outcome.response.latency_budget_ms));
    }

    write_ok(stream, &payload)
}

/// Write the uniform `200 OK` response. Denial is a destination, never a status.
fn write_ok(stream: TcpStream, payload: &str) -> std::io::Result<()> {
    let response = format!(
        "HTTP/1.1 200 OK\r\nContent-Type: text/plain\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        payload.len(),
        payload
    );
    let mut stream = stream;
    stream.write_all(response.as_bytes())?;
    stream.flush()
}

/// Minimal blocking HTTP POST to the shadow process, carrying the portal key.
fn http_post(addr: &str, portal_key_hex: &str, body: &str) -> std::io::Result<String> {
    let mut stream = TcpStream::connect(addr)?;
    let req = format!(
        "POST /run HTTP/1.1\r\nHost: {addr}\r\n{PORTAL_HEADER}: {portal_key_hex}\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        body.len(),
        body
    );
    stream.write_all(req.as_bytes())?;
    stream.flush()?;
    let mut reader = BufReader::new(stream);
    let mut status = String::new();
    reader.read_line(&mut status)?;
    let mut content_length = 0usize;
    loop {
        let mut h = String::new();
        if reader.read_line(&mut h)? == 0 {
            break;
        }
        let t = h.trim_end();
        if t.is_empty() {
            break;
        }
        if let Some((k, v)) = t.split_once(':') {
            if k.trim().eq_ignore_ascii_case("content-length") {
                content_length = v.trim().parse().unwrap_or(0);
            }
        }
    }
    let mut buf = vec![0u8; content_length];
    reader.read_exact(&mut buf)?;
    Ok(String::from_utf8_lossy(&buf).to_string())
}

/// The portal destination process. It serves ONLY the key-seeded shadow world:
/// it reads the portal key from the internal header, rebuilds the world from the
/// key alone, and answers. It holds no real moonshine and no per-connection
/// state - the wormhole carries everything in the key.
pub fn shadow_serve(addr: &str) -> std::io::Result<()> {
    let listener = TcpListener::bind(addr)?;
    for stream in listener.incoming() {
        let stream = match stream {
            Ok(s) => s,
            Err(_) => continue,
        };
        thread::spawn(move || {
            let _ = shadow_handle(stream);
        });
    }
    Ok(())
}

fn shadow_handle(stream: TcpStream) -> std::io::Result<()> {
    let mut reader = BufReader::new(stream.try_clone()?);
    let mut request_line = String::new();
    reader.read_line(&mut request_line)?;

    let mut content_length = 0usize;
    let mut key = PortalKey::UNIT;
    loop {
        let mut line = String::new();
        if reader.read_line(&mut line)? == 0 {
            break;
        }
        let trimmed = line.trim_end();
        if trimmed.is_empty() {
            break;
        }
        if let Some((k, v)) = trimmed.split_once(':') {
            let name = k.trim().to_ascii_lowercase();
            if name == PORTAL_HEADER {
                key = PortalKey::from_hex(v.trim()).unwrap_or(PortalKey::UNIT);
            } else if name == "content-length" {
                content_length = v.trim().parse().unwrap_or(0);
            }
        }
    }
    let mut body = vec![0u8; content_length];
    if content_length > 0 {
        reader.read_exact(&mut body)?;
    }
    let command = String::from_utf8_lossy(&body);

    // Rebuild the identical world from the key alone, run, answer. No execution.
    let world = ShadowWorld::from_key(key);
    write_ok(stream, &world.run(command.trim()))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn quiet_peer_is_not_flagged_but_sweeper_is() {
        let tracker = PeerTracker::new();
        // A quiet peer touching one path, once.
        let quiet = tracker.observe("10.0.0.1", "/run");
        assert_eq!(quiet.distinct_paths, 1);

        // A sweeper enumerating many distinct paths from one address.
        for i in 0..40 {
            tracker.observe("10.0.0.2", &format!("/p{i}"));
        }
        let swept = tracker.observe("10.0.0.2", "/p41");
        assert!(swept.distinct_paths >= 40);
        assert!(crate::detect::observe(&swept).adversarial, "a path sweep must read as observation");
    }
}
